{"file_path": "/app/ars.R", "content": "################################################################################
# Adaptive Rejection Sampling (ARS)
# Based on Gilks, W.R. & Wild, P. (1992)
# "Adaptive Rejection Sampling for Gibbs Sampling"
# Journal of the Royal Statistical Society: Series C, 41(2), 337-348.
################################################################################

# ==============================================================================
# Auxiliary / Modular Functions
# ==============================================================================

#' Compute the log of the (possibly unnormalized) density.
#'
#' @param x   Numeric vector of points.
#' @param f   A function representing the (possibly unnormalized) density.
#' @return    Numeric vector of log-density values.
h_func <- function(x, f) {
  fx <- f(x)
  if (any(fx < 0)) {
    stop("Density function returned negative values. Density must be non-negative.")
  }
  # Replace 0 with -Inf in log space
  result <- ifelse(fx > 0, log(fx), -Inf)
  return(result)
}

#' Compute the derivative of h(x) = log(f(x)) numerically.
#'
#' @param x   Numeric vector of points.
#' @param f   Density function.
#' @param eps Step size for numerical differentiation.
#' @return    Numeric vector of derivative values.
h_deriv <- function(x, f, eps = 1e-7) {
  (h_func(x + eps, f) - h_func(x - eps, f)) / (2 * eps)
}

#' Initialize abscissae (starting points) for the ARS algorithm.
#'
#' We pick k starting points in the domain [lb, ub]. We ensure that the
#' derivative of h at the leftmost point is positive and at the rightmost
#' point is negative (required for the upper hull to be well-defined when
#' the domain is unbounded).
#'
#' @param k   Number of initial abscissae (>= 2).
#' @param lb  Lower bound of the domain.
#' @param ub  Upper bound of the domain.
#' @param f   Density function.
#' @return    Sorted numeric vector of initial abscissae.
initialize_abscissae <- function(k, lb, ub, f) {
  if (k < 2) stop("Need at least 2 initial abscissae.")

  # Handle infinite bounds: pick sensible finite starting points
  if (is.infinite(lb) && is.infinite(ub)) {
    # Try to find a mode near 0 and spread around it
    x_init <- seq(-5, 5, length.out = k)
  } else if (is.infinite(lb)) {
    x_init <- seq(ub - k * 2, ub - 1, length.out = k)
  } else if (is.infinite(ub)) {
    x_init <- seq(lb + 1, lb + k * 2, length.out = k)
  } else {
    x_init <- seq(lb + (ub - lb) * 0.1, ub - (ub - lb) * 0.1, length.out = k)
  }

  # Ensure h is finite at all initial points
  h_vals <- h_func(x_init, f)
  if (any(is.infinite(h_vals) & h_vals == -Inf)) {
    # Try shifting towards the region of positive density
    # Find one point with finite h by searching
    test_pts <- seq(
      ifelse(is.infinite(lb), -100, lb + 0.01),
      ifelse(is.infinite(ub), 100, ub - 0.01),
      length.out = 1000
    )
    test_h <- h_func(test_pts, f)
    valid <- test_pts[is.finite(test_h)]
    if (length(valid) < k) {
      stop("Could not find enough points with positive density in the domain.")
    }
    # Pick k evenly spaced points from the valid region
    idx <- round(seq(1, length(valid), length.out = k))
    x_init <- valid[idx]
  }

  # Check derivative conditions for unbounded domains
  h_prime <- h_deriv(x_init, f)

  if (is.infinite(lb)) {
    # Need h'(x_1) > 0
    if (h_prime[1] <= 0) {
      # Shift left point further left until derivative is positive
      x_try <- x_init[1]
      for (i in 1:50) {
        x_try <- x_try - 2^i
        if (x_try <= lb) break
        hp <- h_deriv(x_try, f)
        hv <- h_func(x_try, f)
        if (hp > 0 && is.finite(hv)) {
          x_init[1] <- x_try
          break
        }
      }
    }
  }

  if (is.infinite(ub)) {
    # Need h'(x_k) < 0
    if (h_prime[length(x_init)] >= 0) {
      x_try <- x_init[length(x_init)]
      for (i in 1:50) {
        x_try <- x_try + 2^i
        if (x_try >= ub) break
        hp <- h_deriv(x_try, f)
        hv <- h_func(x_try, f)
        if (hp < 0 && is.finite(hv)) {
          x_init[length(x_init)] <- x_try
          break
        }
      }
    }
  }

  x_init <- sort(x_init)

  # Final check
  h_prime_final <- h_deriv(x_init, f)
  if (is.infinite(lb) && h_prime_final[1] <= 0) {
    stop("Cannot find an initial point where h'(x) > 0 at the left boundary. ",
         "The density may not be log-concave or the domain may need adjustment.")
  }
  if (is.infinite(ub) && h_prime_final[length(x_init)] >= 0) {
    stop("Cannot find an initial point where h'(x) < 0 at the right boundary. ",
         "The density may not be log-concave or the domain may need adjustment.")
  }

  return(x_init)
}

#' Check log-concavity: h'' <= 0. We check that the slopes between
#' consecutive abscissae are non-increasing.
#'
#' @param x_k Sorted numeric vector of abscissae.
#' @param h_k Numeric vector of h values at abscissae.
#' @return    TRUE if log-concavity check passes, otherwise stops with error.
check_log_concavity <- function(x_k, h_k) {
  n <- length(x_k)
  if (n < 3) return(TRUE)

  slopes <- diff(h_k) / diff(x_k)
  # Allow small numerical tolerance
  for (i in 2:length(slopes)) {
    if (slopes[i] > slopes[i - 1] + 1e-6) {
      stop("Log-concavity violation detected! The density does not appear to be ",
           "log-concave. Slopes between abscissae are not non-increasing.\n",
           "  slope[", i - 1, "] = ", slopes[i - 1], "\n",
           "  slope[", i, "] = ", slopes[i])
    }
  }
  return(TRUE)
}

#' Compute the intersection points z_j of the tangent lines at adjacent
#' abscissae.
#'
#' For tangent lines at x_j and x_{j+1}:
#'   z_j = (h(x_{j+1}) - h(x_j) - x_{j+1}*h'(x_{j+1}) + x_j*h'(x_j))
#'         / (h'(x_j) - h'(x_{j+1}))
#'
#' @param x_k     Sorted abscissae.
#' @param h_k     h values at abscissae.
#' @param hprime_k  h' values at abscissae.
#' @param lb      Lower bound.
#' @param ub      Upper bound.
#' @return        Numeric vector of intersection points (length = length(x_k)+1),
#'                including lb and ub as boundary values.
compute_z <- function(x_k, h_k, hprime_k, lb, ub) {
  k <- length(x_k)
  z <- numeric(k + 1)
  z[1] <- lb
  z[k + 1] <- ub

  if (k >= 2) {
    for (j in 1:(k - 1)) {
      denom <- hprime_k[j] - hprime_k[j + 1]
      if (abs(denom) < 1e-15) {
        # Parallel tangent lines; midpoint is a reasonable choice
        z[j + 1] <- (x_k[j] + x_k[j + 1]) / 2
      } else {
        z[j + 1] <- (h_k[j + 1] - h_k[j] - x_k[j + 1] * hprime_k[j + 1] +
                       x_k[j] * hprime_k[j]) / denom
      }
    }
  }
  return(z)
}

#' Evaluate the upper hull u_k(x) at point x.
#'
#' The upper hull is the piecewise linear function formed by tangent lines.
#' For x in [z_j, z_{j+1}], u_k(x) = h(x_j) + (x - x_j) * h'(x_j).
#'
#' @param x        Numeric vector of evaluation points.
#' @param x_k      Sorted abscissae.
#' @param h_k      h values at abscissae.
#' @param hprime_k h' values at abscissae.
#' @param z        Intersection points from compute_z.
#' @return         Numeric vector of upper hull values.
upper_hull <- function(x, x_k, h_k, hprime_k, z) {
  k <- length(x_k)
  result <- numeric(length(x))

  for (i in seq_along(x)) {
    # Find which segment x[i] falls in
    # z[1] <= z[2] <= ... <= z[k+1]
    # segment j: z[j] <= x < z[j+1], use tangent at x_k[j]
    j <- findInterval(x[i], z, rightmost.closed = TRUE)
    j <- max(1, min(j, k))
    result[i] <- h_k[j] + (x[i] - x_k[j]) * hprime_k[j]
  }
  return(result)
}

#' Evaluate the lower hull l_k(x) at point x.
#'
#' The lower hull is the piecewise linear function connecting adjacent abscissae.
#' For x in [x_j, x_{j+1}]:
#'   l_k(x) = ((x_{j+1}-x)*h(x_j) + (x-x_j)*h(x_{j+1})) / (x_{j+1}-x_j)
#' For x outside [x_1, x_k]: l_k(x) = -Inf.
#'
#' @param x   Numeric vector of evaluation points.
#' @param x_k Sorted abscissae.
#' @param h_k h values at abscissae.
#' @return    Numeric vector of lower hull values.
lower_hull <- function(x, x_k, h_k) {
  k <- length(x_k)
  result <- rep(-Inf, length(x))

  for (i in seq_along(x)) {
    if (x[i] >= x_k[1] && x[i] <= x_k[k]) {
      j <- findInterval(x[i], x_k, rightmost.closed = TRUE)
      j <- max(1, min(j, k - 1))
      result[i] <- ((x_k[j + 1] - x[i]) * h_k[j] +
                      (x[i] - x_k[j]) * h_k[j + 1]) / (x_k[j + 1] - x_k[j])
    }
  }
  return(result)
}

#' Sample from the piecewise-exponential envelope defined by the upper hull.
#'
#' The sampling distribution s_k(x) is proportional to exp(u_k(x)).
#' Each piece is an exponential (or uniform) segment.
#'
#' @param n        Number of points to sample.
#' @param x_k      Sorted abscissae.
#' @param h_k      h values at abscissae.
#' @param hprime_k h' values at abscissae.
#' @param z        Intersection points.
#' @return         Numeric vector of samples from the envelope.
sample_envelope <- function(n, x_k, h_k, hprime_k, z) {
  k <- length(x_k)

  # Compute the integral of exp(u_k(x)) over each piece
  # Piece j: [z[j], z[j+1]], tangent at x_k[j]
  # integral = exp(h_k[j] - x_k[j]*hprime_k[j]) *
  #            integral of exp(hprime_k[j]*x) dx from z[j] to z[j+1]

  log_areas <- numeric(k)
  for (j in 1:k) {
    a <- z[j]
    b <- z[j + 1]
    slope <- hprime_k[j]
    intercept <- h_k[j] - x_k[j] * slope  # u(x) = intercept + slope*x

    if (abs(slope) < 1e-10) {
      # Approximate as uniform
      if (is.infinite(b - a)) {
        log_areas[j] <- -Inf  # This segment has infinite area - shouldn't happen
      } else {
        log_areas[j] <- intercept + log(b - a)
      }
    } else {
      # integral of exp(intercept + slope*x) from a to b
      # = exp(intercept)/slope * (exp(slope*b) - exp(slope*a))
      log_val_b <- intercept + slope * b
      log_val_a <- intercept + slope * a

      if (is.infinite(b)) {
        # slope must be < 0 for convergence
        # integral = exp(intercept + slope*a) / (-slope)
        log_areas[j] <- intercept + slope * a - log(-slope)
      } else if (is.infinite(a)) {
        # slope must be > 0 for convergence
        # integral = exp(intercept + slope*b) / slope
        log_areas[j] <- intercept + slope * b - log(slope)
      } else {
        # Use log-sum-exp for numerical stability
        if (slope > 0) {
          log_areas[j] <- log_val_b + log(1 - exp(log_val_a - log_val_b)) - log(slope)
        } else {
          log_areas[j] <- log_val_a + log(1 - exp(log_val_b - log_val_a)) - log(-slope)
        }
      }
    }
  }

  # Normalize to get probabilities for each segment
  log_area_max <- max(log_areas[is.finite(log_areas)])
  areas <- exp(log_areas - log_area_max)
  probs <- areas / sum(areas)

  # Sample segments
  segments <- sample(1:k, n, replace = TRUE, prob = probs)

  # Sample within each segment using inverse CDF of truncated exponential
  samples <- numeric(n)
  for (i in 1:n) {
    j <- segments[i]
    a <- z[j]
    b <- z[j + 1]
    slope <- hprime_k[j]

    u <- runif(1)

    if (abs(slope) < 1e-10) {
      # Uniform on [a, b]
      samples[i] <- a + u * (b - a)
    } else {
      # Inverse CDF of truncated exponential
      if (is.infinite(a) && a < 0) {
        # slope > 0, integral from -Inf to b: exp(slope*x)/slope evaluated at b
        # CDF: exp(slope*(x - b)) for x <= b
        # Inverse: b + log(u)/slope
        samples[i] <- b + log(u) / slope
      } else if (is.infinite(b) && b > 0) {
        # slope < 0, integral from a to Inf: exp(slope*a)/(-slope)
        # CDF: 1 - exp(slope*(x - a)) for x >= a
        # Inverse: a + log(1 - u)/slope  (note slope < 0)
        samples[i] <- a + log(1 - u) / slope  # slope < 0 so this works
      } else {
        # Finite interval [a, b]
        # CDF(x) = (exp(slope*x) - exp(slope*a)) / (exp(slope*b) - exp(slope*a))
        # Inverse: log(exp(slope*a) + u*(exp(slope*b) - exp(slope*a))) / slope
        exp_sa <- exp(slope * a)
        exp_sb <- exp(slope * b)
        samples[i] <- log(exp_sa + u * (exp_sb - exp_sa)) / slope
      }
    }
  }

  return(samples)
}

#' Perform the squeeze test.
#'
#' Accept x* if w <= exp(l_k(x*) - u_k(x*)).
#'
#' @param x_star  Candidate point.
#' @param w       Uniform random value in [0, 1].
#' @param l_val   Lower hull value at x_star.
#' @param u_val   Upper hull value at x_star.
#' @return        TRUE if squeeze test passes (accept), FALSE otherwise.
squeeze_test <- function(x_star, w, l_val, u_val) {
  return(w <= exp(l_val - u_val))
}

#' Perform the rejection test.
#'
#' Accept x* if w <= exp(h(x*) - u_k(x*)).
#'
#' @param x_star  Candidate point.
#' @param w       Uniform random value in [0,1].
#' @param h_val   True log-density at x_star.
#' @param u_val   Upper hull value at x_star.
#' @return        TRUE if rejection test passes (accept), FALSE otherwise.
rejection_test <- function(x_star, w, h_val, u_val) {
  return(w <= exp(h_val - u_val))
}

#' Update the abscissae set by inserting a new point.
#'
#' @param x_k      Current sorted abscissae.
#' @param h_k      Current h values.
#' @param hprime_k Current h' values.
#' @param x_new    New point to insert.
#' @param h_new    h value at new point.
#' @param hprime_new h' value at new point.
#' @return         List with updated x_k, h_k, hprime_k.
update_abscissae <- function(x_k, h_k, hprime_k, x_new, h_new, hprime_new) {
  # Find insertion position
  pos <- findInterval(x_new, x_k) + 1
  x_k <- append(x_k, x_new, after = pos - 1)
  h_k <- append(h_k, h_new, after = pos - 1)
  hprime_k <- append(hprime_k, hprime_new, after = pos - 1)
  return(list(x_k = x_k, h_k = h_k, hprime_k = hprime_k))
}

#' Validate inputs for the ars function.
#'
#' @param n    Number of samples.
#' @param f    Density function.
#' @param lb   Lower bound.
#' @param ub   Upper bound.
#' @param k    Number of initial abscissae.
validate_inputs <- function(n, f, lb, ub, k) {
  if (!is.numeric(n) || length(n) != 1 || n != floor(n) || n < 1) {
    stop("'n' must be a positive integer.")
  }
  if (!is.function(f)) {
    stop("'f' must be a function.")
  }
  if (!is.numeric(lb) || length(lb) != 1) {
    stop("'lb' must be a single numeric value.")
  }
  if (!is.numeric(ub) || length(ub) != 1) {
    stop("'ub' must be a single numeric value.")
  }
  if (lb >= ub) {
    stop("Lower bound 'lb' must be strictly less than upper bound 'ub'.")
  }
  if (!is.numeric(k) || length(k) != 1 || k != floor(k) || k < 2) {
    stop("'k' (number of initial abscissae) must be an integer >= 2.")
  }
  # Test that f can be evaluated
  test_pt <- if (is.finite(lb) && is.finite(ub)) {
    (lb + ub) / 2
  } else if (is.finite(lb)) {
    lb + 1
  } else if (is.finite(ub)) {
    ub - 1
  } else {
    0
  }
  tryCatch({
    val <- f(test_pt)
    if (!is.numeric(val) || length(val) != 1) {
      stop("'f' must return a single numeric value for a single input.")
    }
    if (is.na(val) || is.nan(val)) {
      stop("'f' returned NA/NaN. Ensure the function is valid over the domain.")
    }
    if (val < 0) {
      stop("'f' returned a negative value. Density must be non-negative.")
    }
  }, error = function(e) {
    stop("Error evaluating 'f': ", e$message)
  })
  return(TRUE)
}


# ==============================================================================
# Main ARS Function
# ==============================================================================

#' Adaptive Rejection Sampling (ARS)
#'
#' Generates samples from a target distribution using the adaptive rejection
#' sampling method of Gilks & Wild (1992).
#'
#' @param n     Number of samples to generate (positive integer).
#' @param f     Function computing the (possibly unnormalized) density.
#'              Must accept a numeric vector and return non-negative values.
#'              E.g., function(x) dnorm(x, 0, 1).
#' @param lb    Lower bound of the support (default -Inf).
#' @param ub    Upper bound of the support (default Inf).
#' @param k     Number of initial abscissae (default 5, must be >= 2).
#' @return      Numeric vector of n samples from the target distribution.
#'
#' @examples
#' # Sample from standard normal
#' samples <- ars(1000, dnorm)
#'
#' # Sample from Exp(1) on (0, Inf)
#' samples <- ars(1000, dexp, lb = 0)
ars <- function(n, f, lb = -Inf, ub = Inf, k = 5) {

  # --- Input Validation ---
  validate_inputs(n, f, lb, ub, k)

  # --- Initialization ---
  x_k <- initialize_abscissae(k, lb, ub, f)
  h_k <- h_func(x_k, f)
  hprime_k <- h_deriv(x_k, f)

  # Check initial log-concavity
  check_log_concavity(x_k, h_k)

  # Compute initial intersection points
  z <- compute_z(x_k, h_k, hprime_k, lb, ub)

  # --- Sampling Loop ---
  samples <- numeric(n)
  count <- 0
  max_iter <- n * 100  # Safety limit
  iter <- 0

  while (count < n && iter < max_iter) {
    iter <- iter + 1

    # Step 1: Sample x* from the envelope s_k(x)
    x_star <- sample_envelope(1, x_k, h_k, hprime_k, z)

    # Check that x_star is within bounds
    if (x_star <= lb || x_star >= ub) next

    # Step 2: Generate w ~ Uniform(0,1)
    w <- runif(1)

    # Step 3: Evaluate upper and lower hulls
    u_val <- upper_hull(x_star, x_k, h_k, hprime_k, z)
    l_val <- lower_hull(x_star, x_k, h_k)

    # Step 4: Squeeze test
    if (squeeze_test(x_star, w, l_val, u_val)) {
      count <- count + 1
      samples[count] <- x_star
    } else {
      # Step 5: Evaluate h(x*)
      h_star <- h_func(x_star, f)
      hprime_star <- h_deriv(x_star, f)

      # Step 6: Rejection test
      if (rejection_test(x_star, w, h_star, u_val)) {
        count <- count + 1
        samples[count] <- x_star
      }

      # Step 7: Update abscissae (regardless of accept/reject)
      updated <- update_abscissae(x_k, h_k, hprime_k, x_star, h_star, hprime_star)
      x_k <- updated$x_k
      h_k <- updated$h_k
      hprime_k <- updated$hprime_k

      # Re-check log-concavity with new point
      check_log_concavity(x_k, h_k)

      # Recompute intersection points
      z <- compute_z(x_k, h_k, hprime_k, lb, ub)
    }
  }

  if (count < n) {
    warning("ARS did not generate the requested number of samples. Got ", count,
            " out of ", n, ".")
    samples <- samples[1:count]
  }

  return(samples)
}


# ==============================================================================
# Test Function
# ==============================================================================

#' Run a suite of formal tests for the ARS implementation.
#'
#' Tests include:
#' - Input validation checks
#' - Sampling from known distributions (Normal, Exponential, Gamma, Beta, Uniform)
#' - Comparison of sample statistics with theoretical values (KS test, mean, sd)
#' - Log-concavity detection
#'
#' Output: For each test, prints the test name and PASS/FAIL status.
test <- function() {
  cat("=" , rep("=", 70), "\n", sep = "")
  cat("  Adaptive Rejection Sampling (ARS) - Test Suite\n")
  cat("=", rep("=", 70), "\n\n", sep = "")

  pass_count <- 0
  fail_count <- 0

  # Helper to report results
  report <- function(test_name, passed, detail = "") {
    if (passed) {
      cat(test_name, ": PASS", sep = "")
      pass_count <<- pass_count + 1
    } else {
      cat(test_name, ": FAIL", sep = "")
      fail_count <<- fail_count + 1
    }
    if (nchar(detail) > 0) cat("  [", detail, "]", sep = "")
    cat("\n")
  }

  # ---------------------------------------------------------------
  # 1. Input Validation Tests
  # ---------------------------------------------------------------
  cat("\n--- Input Validation Tests ---\n\n")

  # Test: negative n
  test_name <- "Reject negative sample count"
  passed <- tryCatch({
    ars(-5, dnorm)
    FALSE
  }, error = function(e) TRUE)
  report(test_name, passed)

  # Test: n = 0
  test_name <- "Reject zero sample count"
  passed <- tryCatch({
    ars(0, dnorm)
    FALSE
  }, error = function(e) TRUE)
  report(test_name, passed)

  # Test: non-numeric n
  test_name <- "Reject non-numeric sample count"
  passed <- tryCatch({
    ars("abc", dnorm)
    FALSE
  }, error = function(e) TRUE)
  report(test_name, passed)

  # Test: non-function f
  test_name <- "Reject non-function density"
  passed <- tryCatch({
    ars(100, "not_a_function")
    FALSE
  }, error = function(e) TRUE)
  report(test_name, passed)

  # Test: lb >= ub
  test_name <- "Reject invalid domain (lb >= ub)"
  passed <- tryCatch({
    ars(100, dnorm, lb = 5, ub = 2)
    FALSE
  }, error = function(e) TRUE)
  report(test_name, passed)

  # Test: lb == ub
  test_name <- "Reject degenerate domain (lb == ub)"
  passed <- tryCatch({
    ars(100, dnorm, lb = 3, ub = 3)
    FALSE
  }, error = function(e) TRUE)
  report(test_name, passed)

  # Test: invalid k
  test_name <- "Reject k < 2"
  passed <- tryCatch({
    ars(100, dnorm, k = 1)
    FALSE
  }, error = function(e) TRUE)
  report(test_name, passed)

  # ---------------------------------------------------------------
  # 2. Log-Concavity Detection Tests
  # ---------------------------------------------------------------
  cat("\n--- Log-Concavity Detection Tests ---\n\n")

  # Cauchy distribution: NOT log-concave
  test_name <- "Detect non-log-concave (Cauchy)"
  passed <- tryCatch({
    ars(1000, dcauchy)
    FALSE
  }, error = function(e) {
    grepl("[Ll]og-concav", e$message) || grepl("concav", e$message, ignore.case = TRUE)
  })
  report(test_name, passed)

  # t-distribution with df=1 (same as Cauchy)
  test_name <- "Detect non-log-concave (t, df=1)"
  passed <- tryCatch({
    ars(1000, function(x) dt(x, df = 1))
    FALSE
  }, error = function(e) TRUE)
  report(test_name, passed)

  # Mixture of two normals (bimodal = not log-concave)
  test_name <- "Detect non-log-concave (bimodal mixture)"
  passed <- tryCatch({
    bimodal <- function(x) 0.5 * dnorm(x, -5, 0.5) + 0.5 * dnorm(x, 5, 0.5)
    ars(1000, bimodal)
    FALSE
  }, error = function(e) TRUE)
  report(test_name, passed)

  # ---------------------------------------------------------------
  # 3. Module / Auxiliary Function Tests
  # ---------------------------------------------------------------
  cat("\n--- Auxiliary Function Tests ---\n\n")

  # Test h_func
  test_name <- "h_func: log of dnorm(0) == log(dnorm(0))"
  hval <- h_func(0, dnorm)
  passed <- abs(hval - log(dnorm(0))) < 1e-10
  report(test_name, passed, paste("h=", round(hval, 6), "expected=", round(log(dnorm(0)), 6)))

  # Test h_func vectorized
  test_name <- "h_func: vectorized evaluation"
  hvals <- h_func(c(-1, 0, 1), dnorm)
  expected <- log(dnorm(c(-1, 0, 1)))
  passed <- all(abs(hvals - expected) < 1e-10)
  report(test_name, passed)

  # Test h_deriv
  test_name <- "h_deriv: derivative of log(dnorm) at 0 approx 0"
  hd <- h_deriv(0, dnorm)
  passed <- abs(hd) < 1e-4
  report(test_name, passed, paste("h'(0) =", round(hd, 8)))

  # Test h_deriv: derivative of log(dnorm) at 1 approx -1
  test_name <- "h_deriv: derivative of log(dnorm) at 1 approx -1"
  hd <- h_deriv(1, dnorm)
  passed <- abs(hd - (-1)) < 1e-4
  report(test_name, passed, paste("h'(1) =", round(hd, 8)))

  # Test upper_hull >= h (by construction)
  test_name <- "Upper hull >= h(x) at test points"
  set.seed(42)
  x_test_abs <- sort(c(-2, -1, 0, 1, 2))
  h_test_abs <- h_func(x_test_abs, dnorm)
  hp_test_abs <- h_deriv(x_test_abs, dnorm)
  z_test <- compute_z(x_test_abs, h_test_abs, hp_test_abs, -Inf, Inf)
  test_pts <- seq(-3, 3, by = 0.1)
  u_vals <- upper_hull(test_pts, x_test_abs, h_test_abs, hp_test_abs, z_test)
  h_vals_test <- h_func(test_pts, dnorm)
  passed <- all(u_vals >= h_vals_test - 1e-6)
  report(test_name, passed)

  # Test lower_hull <= h (by construction)
  test_name <- "Lower hull <= h(x) at test points"
  l_vals <- lower_hull(test_pts, x_test_abs, h_test_abs)
  # Only check where lower hull is defined (not -Inf)
  valid_idx <- which(is.finite(l_vals))
  passed <- all(l_vals[valid_idx] <= h_vals_test[valid_idx] + 1e-6)
  report(test_name, passed)

  # Test check_log_concavity on a log-concave set
  test_name <- "check_log_concavity: passes for normal"
  passed <- tryCatch({
    check_log_concavity(x_test_abs, h_test_abs)
    TRUE
  }, error = function(e) FALSE)
  report(test_name, passed)

  # Test check_log_concavity fails for non-concave
  test_name <- "check_log_concavity: fails for non-concave data"
  passed <- tryCatch({
    # Fabricate non-concave h values
    check_log_concavity(c(1, 2, 3, 4, 5), c(1, 2, 1, 2, 1))
    FALSE
  }, error = function(e) TRUE)
  report(test_name, passed)

  # Test update_abscissae
  test_name <- "update_abscissae: correct insertion"
  upd <- update_abscissae(c(1, 3, 5), c(10, 20, 30), c(-1, -2, -3), 2, 15, -1.5)
  passed <- all(upd$x_k == c(1, 2, 3, 5)) && all(upd$h_k == c(10, 15, 20, 30))
  report(test_name, passed)

  # ---------------------------------------------------------------
  # 4. Distributional Tests (KS test + moment checks)
  # ---------------------------------------------------------------
  cat("\n--- Distributional Tests ---\n\n")

  set.seed(123)
  n_samples <- 5000
  alpha <- 0.01  # significance level for KS test

  # --- Standard Normal N(0,1) ---
  test_name <- "Standard Normal N(0,1): KS test"
  samples_norm <- ars(n_samples, dnorm)
  ks_result <- ks.test(samples_norm, "pnorm")
  passed <- ks_result$p.value > alpha
  report(test_name, passed,
         paste("p=", round(ks_result$p.value, 4),
               "mean=", round(mean(samples_norm), 4),
               "sd=", round(sd(samples_norm), 4)))

  test_name <- "Standard Normal N(0,1): mean ~ 0"
  passed <- abs(mean(samples_norm)) < 0.1
  report(test_name, passed, paste("mean=", round(mean(samples_norm), 4)))

  test_name <- "Standard Normal N(0,1): sd ~ 1"
  passed <- abs(sd(samples_norm) - 1) < 0.15
  report(test_name, passed, paste("sd=", round(sd(samples_norm), 4)))

  # Save normal samples
  writeLines(as.character(samples_norm), "/app/normal_samples.txt")
  cat("  -> Saved normal samples to /app/normal_samples.txt\n")

  # --- Normal N(3, 2^2) ---
  test_name <- "Normal N(3, 4): KS test"
  f_norm32 <- function(x) dnorm(x, mean = 3, sd = 2)
  samples_norm32 <- ars(n_samples, f_norm32)
  ks_result <- ks.test(samples_norm32, "pnorm", mean = 3, sd = 2)
  passed <- ks_result$p.value > alpha
  report(test_name, passed,
         paste("p=", round(ks_result$p.value, 4),
               "mean=", round(mean(samples_norm32), 4),
               "sd=", round(sd(samples_norm32), 4)))

  test_name <- "Normal N(3, 4): mean ~ 3"
  passed <- abs(mean(samples_norm32) - 3) < 0.2
  report(test_name, passed, paste("mean=", round(mean(samples_norm32), 4)))

  test_name <- "Normal N(3, 4): sd ~ 2"
  passed <- abs(sd(samples_norm32) - 2) < 0.3
  report(test_name, passed, paste("sd=", round(sd(samples_norm32), 4)))

  # --- Exponential(1) ---
  test_name <- "Exponential(1): KS test"
  samples_exp <- ars(n_samples, dexp, lb = 0)
  ks_result <- ks.test(samples_exp, "pexp")
  passed <- ks_result$p.value > alpha
  report(test_name, passed,
         paste("p=", round(ks_result$p.value, 4),
               "mean=", round(mean(samples_exp), 4),
               "sd=", round(sd(samples_exp), 4)))

  test_name <- "Exponential(1): mean ~ 1"
  passed <- abs(mean(samples_exp) - 1) < 0.15
  report(test_name, passed, paste("mean=", round(mean(samples_exp), 4)))

  test_name <- "Exponential(1): sd ~ 1"
  passed <- abs(sd(samples_exp) - 1) < 0.15
  report(test_name, passed, paste("sd=", round(sd(samples_exp), 4)))

  # Save exponential samples
  writeLines(as.character(samples_exp), "/app/exponential_samples.txt")
  cat("  -> Saved exponential samples to /app/exponential_samples.txt\n")

  # --- Exponential(2) ---
  test_name <- "Exponential(2): KS test"
  f_exp2 <- function(x) dexp(x, rate = 2)
  samples_exp2 <- ars(n_samples, f_exp2, lb = 0)
  ks_result <- ks.test(samples_exp2, "pexp", rate = 2)
  passed <- ks_result$p.value > alpha
  report(test_name, passed,
         paste("p=", round(ks_result$p.value, 4),
               "mean=", round(mean(samples_exp2), 4),
               "sd=", round(sd(samples_exp2), 4)))

  test_name <- "Exponential(2): mean ~ 0.5"
  passed <- abs(mean(samples_exp2) - 0.5) < 0.1
  report(test_name, passed, paste("mean=", round(mean(samples_exp2), 4)))

  # --- Gamma(3,1) (log-concave for shape >= 1) ---
  test_name <- "Gamma(3,1): KS test"
  f_gamma <- function(x) dgamma(x, shape = 3, rate = 1)
  samples_gamma <- ars(n_samples, f_gamma, lb = 0)
  ks_result <- ks.test(samples_gamma, "pgamma", shape = 3, rate = 1)
  passed <- ks_result$p.value > alpha
  report(test_name, passed,
         paste("p=", round(ks_result$p.value, 4),
               "mean=", round(mean(samples_gamma), 4),
               "sd=", round(sd(samples_gamma), 4)))

  test_name <- "Gamma(3,1): mean ~ 3"
  passed <- abs(mean(samples_gamma) - 3) < 0.3
  report(test_name, passed, paste("mean=", round(mean(samples_gamma), 4)))

  test_name <- "Gamma(3,1): sd ~ sqrt(3)"
  passed <- abs(sd(samples_gamma) - sqrt(3)) < 0.3
  report(test_name, passed, paste("sd=", round(sd(samples_gamma), 4)))

  # --- Beta(2,5) on (0,1) (log-concave for a,b >= 1) ---
  test_name <- "Beta(2,5): KS test"
  f_beta <- function(x) dbeta(x, shape1 = 2, shape2 = 5)
  samples_beta <- ars(n_samples, f_beta, lb = 0, ub = 1)
  ks_result <- ks.test(samples_beta, "pbeta", shape1 = 2, shape2 = 5)
  passed <- ks_result$p.value > alpha
  report(test_name, passed,
         paste("p=", round(ks_result$p.value, 4),
               "mean=", round(mean(samples_beta), 4),
               "sd=", round(sd(samples_beta), 4)))

  test_name <- "Beta(2,5): mean ~ 2/7"
  passed <- abs(mean(samples_beta) - 2/7) < 0.05
  report(test_name, passed, paste("mean=", round(mean(samples_beta), 4)))

  # --- Uniform(0,1) (log-concave) ---
  test_name <- "Uniform(0,1): KS test"
  f_unif <- function(x) dunif(x, 0, 1)
  samples_unif <- ars(n_samples, f_unif, lb = 0, ub = 1)
  ks_result <- ks.test(samples_unif, "punif")
  passed <- ks_result$p.value > alpha
  report(test_name, passed,
         paste("p=", round(ks_result$p.value, 4),
               "mean=", round(mean(samples_unif), 4),
               "sd=", round(sd(samples_unif), 4)))

  test_name <- "Uniform(0,1): mean ~ 0.5"
  passed <- abs(mean(samples_unif) - 0.5) < 0.05
  report(test_name, passed, paste("mean=", round(mean(samples_unif), 4)))

  # --- Logistic(0,1) (log-concave) ---
  test_name <- "Logistic(0,1): KS test"
  samples_logis <- ars(n_samples, dlogis)
  ks_result <- ks.test(samples_logis, "plogis")
  passed <- ks_result$p.value > alpha
  report(test_name, passed,
         paste("p=", round(ks_result$p.value, 4),
               "mean=", round(mean(samples_logis), 4),
               "sd=", round(sd(samples_logis), 4)))

  test_name <- "Logistic(0,1): mean ~ 0"
  passed <- abs(mean(samples_logis)) < 0.15
  report(test_name, passed, paste("mean=", round(mean(samples_logis), 4)))

  # ---------------------------------------------------------------
  # Summary
  # ---------------------------------------------------------------
  cat("\n", rep("=", 71), "\n", sep = "")
  cat("  SUMMARY: ", pass_count, " passed, ", fail_count, " failed, ",
      pass_count + fail_count, " total\n", sep = "")
  cat(rep("=", 71), "\n", sep = "")

  invisible(list(pass = pass_count, fail = fail_count))
}

# Run tests if this file is executed directly
if (sys.nframe() == 0) {
  test()
}
"}
